mapper.select:
SELECT a.id, a.title, a.content, a.position, a.target_audience AS targetAudience, a.start_time AS startTime, a.end_time AS endTime, a.status, a.created_by AS createdBy, a.view_count AS viewCount, a.created_at AS createdAt, a.updated_at AS updatedAt, au.username AS createdByName FROM announcements a LEFT JOIN admin_users au ON a.created_by = au.id
AND a.status = #{status}
ORDER BY a.created_at DESC LIMIT #{offset}, #{limit}
